1	package golang
2	
3	import (
4		"bufio"
5		"fmt"
6		"sort"
7		"strings"
8	
9		"github.com/sqlc-dev/sqlc/internal/codegen/golang/opts"
10		"github.com/sqlc-dev/sqlc/internal/codegen/sdk"
11		"github.com/sqlc-dev/sqlc/internal/inflection"
12		"github.com/sqlc-dev/sqlc/internal/metadata"
13		"github.com/sqlc-dev/sqlc/internal/plugin"
14	)
15	
16	func buildEnums(req *plugin.GenerateRequest, options *opts.Options) []Enum {
17		var enums []Enum
18		for _, schema := range req.Catalog.Schemas {
19			if schema.Name == "pg_catalog" || schema.Name == "information_schema" {
20				continue
21			}
22			for _, enum := range schema.Enums {
23				var enumName string
24				if schema.Name == req.Catalog.DefaultSchema {
25					enumName = enum.Name
26				} else {
27					enumName = schema.Name + "_" + enum.Name
28				}
29	
30				e := Enum{
31					Name:      StructName(enumName, options),
32					Comment:   enum.Comment,
33					NameTags:  map[string]string{},
34					ValidTags: map[string]string{},
35				}
36				if options.EmitJsonTags {
37					e.NameTags["json"] = JSONTagName(enumName, options)
38					e.ValidTags["json"] = JSONTagName("valid", options)
39				}
40	
41				seen := make(map[string]struct{}, len(enum.Vals))
42				for i, v := range enum.Vals {
43					value := EnumReplace(v)
44					if _, found := seen[value]; found || value == "" {
45						value = fmt.Sprintf("value_%d", i)
46					}
47					e.Constants = append(e.Constants, Constant{
48						Name:  StructName(enumName+"_"+value, options),
49						Value: v,
50						Type:  e.Name,
51					})
52					seen[value] = struct{}{}
53				}
54				enums = append(enums, e)
55			}
56		}
57		if len(enums) > 0 {
58			sort.Slice(enums, func(i, j int) bool { return enums[i].Name < enums[j].Name })
59		}
60		return enums
61	}
62	
63	func buildStructs(req *plugin.GenerateRequest, options *opts.Options) []Struct {
64		var structs []Struct
65		for _, schema := range req.Catalog.Schemas {
66			if schema.Name == "pg_catalog" || schema.Name == "information_schema" {
67				continue
68			}
69			for _, table := range schema.Tables {
70				var tableName string
71				if schema.Name == req.Catalog.DefaultSchema {
72					tableName = table.Rel.Name
73				} else {
74					tableName = schema.Name + "_" + table.Rel.Name
75				}
76				structName := tableName
77				if !options.EmitExactTableNames {
78					structName = inflection.Singular(inflection.SingularParams{
79						Name:       structName,
80						Exclusions: options.InflectionExcludeTableNames,
81					})
82				}
83				s := Struct{
84					Table:   &plugin.Identifier{Schema: schema.Name, Name: table.Rel.Name},
85					Name:    StructName(structName, options),
86					Comment: table.Comment,
87				}
88				for _, column := range table.Columns {
89					tags := map[string]string{}
90					if options.EmitDbTags {
91						tags["db"] = column.Name
92					}
93					if options.EmitJsonTags {
94						tags["json"] = JSONTagName(column.Name, options)
95					}
96					addExtraGoStructTags(tags, req, options, column)
97					s.Fields = append(s.Fields, Field{
98						Name:    StructName(column.Name, options),
99						Type:    goType(req, options, column),
100						Tags:    tags,
101						Comment: column.Comment,
102					})
103				}
104				structs = append(structs, s)
105			}
106		}
107		if len(structs) > 0 {
108			sort.Slice(structs, func(i, j int) bool { return structs[i].Name < structs[j].Name })
109		}
110		return structs
111	}
112	
113	type goColumn struct {
114		id int
115		*plugin.Column
116		embed *goEmbed
117	}
118	
119	type goEmbed struct {
120		modelType string
121		modelName string
122		fields    []Field
123	}
124	
125	// look through all the structs and attempt to find a matching one to embed
126	// We need the name of the struct and its field names.
127	func newGoEmbed(embed *plugin.Identifier, structs []Struct, defaultSchema string) *goEmbed {
128		if embed == nil {
129			return nil
130		}
131	
132		for _, s := range structs {
133			embedSchema := defaultSchema
134			if embed.Schema != "" {
135				embedSchema = embed.Schema
136			}
137	
138			// compare the other attributes
139			if embed.Catalog != s.Table.Catalog || embed.Name != s.Table.Name || embedSchema != s.Table.Schema {
140				continue
141			}
142	
143			fields := make([]Field, len(s.Fields))
144			copy(fields, s.Fields)
145	
146			return &goEmbed{
147				modelType: s.Name,
148				modelName: s.Name,
149				fields:    fields,
150			}
151		}
152	
153		return nil
154	}
155	
156	func columnName(c *plugin.Column, pos int) string {
157		if c.Name != "" {
158			return c.Name
159		}
160		return fmt.Sprintf("column_%d", pos+1)
161	}
162	
163	func paramName(p *plugin.Parameter) string {
164		if p.Column.Name != "" {
165			return argName(p.Column.Name)
166		}
167		return fmt.Sprintf("dollar_%d", p.Number)
168	}
169	
170	func argName(name string) string {
171		out := ""
172		for i, p := range strings.Split(name, "_") {
173			if i == 0 {
174				out += strings.ToLower(p)
175			} else if p == "id" {
176				out += "ID"
177			} else {
178				out += strings.Title(p)
179			}
180		}
181		return out
182	}
183	
184	func buildQueries(req *plugin.GenerateRequest, options *opts.Options, structs []Struct) ([]Query, error) {
185		qs := make([]Query, 0, len(req.Queries))
186		for _, query := range req.Queries {
187			if query.Name == "" {
188				continue
189			}
190			if query.Cmd == "" {
191				continue
192			}
193	
194			var constantName string
195			if options.EmitExportedQueries {
196				constantName = sdk.Title(query.Name)
197			} else {
198				constantName = sdk.LowerTitle(query.Name)
199			}
200	
201			comments := query.Comments
202			if options.EmitSqlAsComment {
203				if len(comments) == 0 {
204					comments = append(comments, query.Name)
205				}
206				comments = append(comments, " ")
207				scanner := bufio.NewScanner(strings.NewReader(query.Text))
208				for scanner.Scan() {
209					line := scanner.Text()
210					comments = append(comments, "  "+line)
211				}
212				if err := scanner.Err(); err != nil {
213					return nil, err
214				}
215			}
216	
217			gq := Query{
218				Cmd:          query.Cmd,
219				ConstantName: constantName,
220				FieldName:    sdk.LowerTitle(query.Name) + "Stmt",
221				MethodName:   query.Name,
222				SourceName:   query.Filename,
223				SQL:          query.Text,
224				Comments:     comments,
225				Table:        query.InsertIntoTable,
226			}
227			sqlpkg := parseDriver(options.SqlPackage)
228	
229			qpl := int(*options.QueryParameterLimit)
230	
231			if len(query.Params) == 1 && qpl != 0 {
232				p := query.Params[0]
233				gq.Arg = QueryValue{
234					Name:      escape(paramName(p)),
235					DBName:    p.Column.GetName(),
236					Typ:       goType(req, options, p.Column),
237					SQLDriver: sqlpkg,
238					Column:    p.Column,
239				}
240			} else if len(query.Params) >= 1 {
241				var cols []goColumn
242				for _, p := range query.Params {
243					cols = append(cols, goColumn{
244						id:     int(p.Number),
245						Column: p.Column,
246					})
247				}
248				s, err := columnsToStruct(req, options, gq.MethodName+"Params", cols, false)
249				if err != nil {
250					return nil, err
251				}
252				gq.Arg = QueryValue{
253					Emit:        true,
254					Name:        "arg",
255					Struct:      s,
256					SQLDriver:   sqlpkg,
257					EmitPointer: options.EmitParamsStructPointers,
258				}
259	
260				// if query params is 2, and query params limit is 4 AND this is a copyfrom, we still want to emit the query's model
261				// otherwise we end up with a copyfrom using a struct without the struct definition
262				if len(query.Params) <= qpl && query.Cmd != ":copyfrom" {
263					gq.Arg.Emit = false
264				}
265			}
266	
267			if len(query.Columns) == 1 && query.Columns[0].EmbedTable == nil {
268				c := query.Columns[0]
269				name := columnName(c, 0)
270				name = strings.Replace(name, "$", "_", -1)
271				gq.Ret = QueryValue{
272					Name:      escape(name),
273					DBName:    name,
274					Typ:       goType(req, options, c),
275					SQLDriver: sqlpkg,
276				}
277			} else if putOutColumns(query) {
278				var gs *Struct
279				var emit bool
280	
281				for _, s := range structs {
282					if len(s.Fields) != len(query.Columns) {
283						continue
284					}
285					same := true
286					for i, f := range s.Fields {
287						c := query.Columns[i]
288						sameName := f.Name == StructName(columnName(c, i), options)
289						sameType := f.Type == goType(req, options, c)
290						sameTable := sdk.SameTableName(c.Table, s.Table, req.Catalog.DefaultSchema)
291						if !sameName || !sameType || !sameTable {
292							same = false
293						}
294					}
295					if same {
296						gs = &s
297						break
298					}
299				}
300	
301				if gs == nil {
302					var columns []goColumn
303					for i, c := range query.Columns {
304						columns = append(columns, goColumn{
305							id:     i,
306							Column: c,
307							embed:  newGoEmbed(c.EmbedTable, structs, req.Catalog.DefaultSchema),
308						})
309					}
310					var err error
311					gs, err = columnsToStruct(req, options, gq.MethodName+"Row", columns, true)
312					if err != nil {
313						return nil, err
314					}
315					emit = true
316				}
317				gq.Ret = QueryValue{
318					Emit:        emit,
319					Name:        "i",
320					Struct:      gs,
321					SQLDriver:   sqlpkg,
322					EmitPointer: options.EmitResultStructPointers,
323				}
324			}
325	
326			qs = append(qs, gq)
327		}
328		sort.Slice(qs, func(i, j int) bool { return qs[i].MethodName < qs[j].MethodName })
329		return qs, nil
330	}
331	
332	var cmdReturnsData = map[string]struct{}{
333		metadata.CmdBatchMany: {},
334		metadata.CmdBatchOne:  {},
335		metadata.CmdMany:      {},
336		metadata.CmdOne:       {},
337	}
338	
339	func putOutColumns(query *plugin.Query) bool {
340		_, found := cmdReturnsData[query.Cmd]
341		return found
342	}
343	
344	// It's possible that this method will generate duplicate JSON tag values
345	//
346	//	Columns: count, count,   count_2
347	//	 Fields: Count, Count_2, Count2
348	//
349	// JSON tags: count, count_2, count_2
350	//
351	// This is unlikely to happen, so don't fix it yet
352	func columnsToStruct(req *plugin.GenerateRequest, options *opts.Options, name string, columns []goColumn, useID bool) (*Struct, error) {
353		gs := Struct{
354			Name: name,
355		}
356		seen := map[string][]int{}
357		suffixes := map[int]int{}
358		for i, c := range columns {
359			colName := columnName(c.Column, i)
360			tagName := colName
361	
362			// override col/tag with expected model name
363			if c.embed != nil {
364				colName = c.embed.modelName
365				tagName = SetCaseStyle(colName, "snake")
366			}
367	
368			fieldName := StructName(colName, options)
369			baseFieldName := fieldName
370			// Track suffixes by the ID of the column, so that columns referring to the same numbered parameter can be
371			// reused.
372			suffix := 0
373			if o, ok := suffixes[c.id]; ok && useID {
374				suffix = o
375			} else if v := len(seen[fieldName]); v > 0 && !c.IsNamedParam {
376				suffix = v + 1
377			}
378			suffixes[c.id] = suffix
379			if suffix > 0 {
380				tagName = fmt.Sprintf("%s_%d", tagName, suffix)
381				fieldName = fmt.Sprintf("%s_%d", fieldName, suffix)
382			}
383			tags := map[string]string{}
384			if options.EmitDbTags {
385				tags["db"] = tagName
386			}
387			if options.EmitJsonTags {
388				tags["json"] = JSONTagName(tagName, options)
389			}
390			addExtraGoStructTags(tags, req, options, c.Column)
391			f := Field{
392				Name:   fieldName,
393				DBName: colName,
394				Tags:   tags,
395				Column: c.Column,
396			}
397			if c.embed == nil {
398				f.Type = goType(req, options, c.Column)
399			} else {
400				f.Type = c.embed.modelType
401				f.EmbedFields = c.embed.fields
402			}
403	
404			gs.Fields = append(gs.Fields, f)
405			if _, found := seen[baseFieldName]; !found {
406				seen[baseFieldName] = []int{i}
407			} else {
408				seen[baseFieldName] = append(seen[baseFieldName], i)
409			}
410		}
411	
412		// If a field does not have a known type, but another
413		// field with the same name has a known type, assign
414		// the known type to the field without a known type
415		for i, field := range gs.Fields {
416			if len(seen[field.Name]) > 1 && field.Type == "interface{}" {
417				for _, j := range seen[field.Name] {
418					if i == j {
419						continue
420					}
421					otherField := gs.Fields[j]
422					if otherField.Type != field.Type {
423						field.Type = otherField.Type
424					}
425					gs.Fields[i] = field
426				}
427			}
428		}
429	
430		err := checkIncompatibleFieldTypes(gs.Fields)
431		if err != nil {
432			return nil, err
433		}
434	
435		return &gs, nil
436	}
437	
438	func checkIncompatibleFieldTypes(fields []Field) error {
439		fieldTypes := map[string]string{}
440		for _, field := range fields {
441			if fieldType, found := fieldTypes[field.Name]; !found {
442				fieldTypes[field.Name] = field.Type
443			} else if field.Type != fieldType {
444				return fmt.Errorf("named param %s has incompatible types: %s, %s", field.Name, field.Type, fieldType)
445			}
446		}
447		return nil
448	}
449	

