func TestBuildQueries_SameColumnAndParamName(t *testing.T) {
	qpl := int32(1)
	options := &opts.Options{
		QueryParameterLimit: &qpl,
	}

	req := &plugin.GenerateRequest{
		Settings: &plugin.Settings{
			Engine: "postgresql",
		},
		Catalog: &plugin.Catalog{
			DefaultSchema: "public",
		},
		Queries: []*plugin.Query{
			{
				Name:     "GetUserByEmail",
				Cmd:      metadata.CmdOne,
				Filename: "query.sql",
				Text:     "SELECT email FROM users WHERE email = $1",
				Columns: []*plugin.Column{
					{
						Name: "email",
						Type: &plugin.Identifier{Name: "text"},
					},
				},
				Params: []*plugin.Parameter{
					{
						Number: 1,
						Column: &plugin.Column{
							Name: "email",
							Type: &plugin.Identifier{Name: "text"},
						},
					},
				},
			},
		},
	}
	qs, err := buildQueries(req, options, nil)
	if err != nil {
		t.Fatalf("buildQueries failed: %v", err)
	}
	if len(qs) != 1 {
		t.Fatalf("expected 1 query, got %d", len(qs))
	}
	q := qs[0]

	// The arg and ret should have different names to avoid collision
	if q.Arg.Name == q.Ret.Name {
		t.Errorf("arg name %q should differ from ret name %q when column and param share the same name", q.Arg.Name, q.Ret.Name)
	}
}

