package golang

import (
	"testing"

	"github.com/sqlc-dev/sqlc/internal/codegen/golang/opts"
	"github.com/sqlc-dev/sqlc/internal/metadata"
	"github.com/sqlc-dev/sqlc/internal/plugin"
)

func TestPutOutColumns_ForZeroColumns(t *testing.T) {
	tests := []struct {
		cmd  string
		want bool
	}{
		{
			cmd:  metadata.CmdExec,
			want: false,
		},
		{
			cmd:  metadata.CmdExecResult,
			want: false,
		},
		{
			cmd:  metadata.CmdExecRows,
			want: false,
		},
		{
			cmd:  metadata.CmdExecLastId,
			want: false,
		},
		{
			cmd:  metadata.CmdMany,
			want: true,
		},
		{
			cmd:  metadata.CmdOne,
			want: true,
		},
		{
			cmd:  metadata.CmdCopyFrom,
			want: false,
		},
		{
			cmd:  metadata.CmdBatchExec,
			want: false,
		},
		{
			cmd:  metadata.CmdBatchMany,
			want: true,
		},
		{
			cmd:  metadata.CmdBatchOne,
			want: true,
		},
	}
	for _, tc := range tests {
		t.Run(tc.cmd, func(t *testing.T) {
			query := &plugin.Query{
				Cmd:     tc.cmd,
				Columns: []*plugin.Column{},
			}
			got := putOutColumns(query)
			if got != tc.want {
				t.Errorf("putOutColumns failed. want %v, got %v", tc.want, got)
			}
		})
	}
}

func TestPutOutColumns_AlwaysTrueWhenQueryHasColumns(t *testing.T) {
	query := &plugin.Query{
		Cmd:     metadata.CmdMany,
		Columns: []*plugin.Column{{}},
	}
	if putOutColumns(query) != true {
		t.Error("should be true when we have columns")
	}
}

func TestBuildQueries_SameColumnAndParamName(t *testing.T) {
	qpl := int32(1)
	options := &opts.Options{
		QueryParameterLimit: &qpl,
	}

	req := &plugin.GenerateRequest{
		Settings: &plugin.Settings{
			Engine: "postgresql",
		},
		Catalog: &plugin.Catalog{
			DefaultSchema: "public",
		},
		Queries: []*plugin.Query{
			{
				Name:     "GetUserByEmail",
				Cmd:      metadata.CmdOne,
				Filename: "query.sql",
				Text:     "SELECT email FROM users WHERE email = $1",
				Columns: []*plugin.Column{
					{
						Name: "email",
						Type: &plugin.Identifier{Name: "text"},
					},
				},
				Params: []*plugin.Parameter{
					{
						Number: 1,
						Column: &plugin.Column{
							Name: "email",
							Type: &plugin.Identifier{Name: "text"},
						},
					},
				},
			},
		},
	}
	qs, err := buildQueries(req, options, nil)
	if err != nil {
		t.Fatalf("buildQueries failed: %v", err)
	}
	if len(qs) != 1 {
		t.Fatalf("expected 1 query, got %d", len(qs))
	}
	q := qs[0]

	// The arg and ret should have different names to avoid collision
	if q.Arg.Name == q.Ret.Name {
		t.Errorf("arg name %q should differ from ret name %q when column and param share the same name", q.Arg.Name, q.Ret.Name)
	}
}

